{
    get
    {
        var (value, _) = GetLargestWholeNumber();
        return value;
    }
}

private (double Value, string Symbol) GetLargestWholeNumber()
{
    double absBytes = Math.Abs(Bytes);
    if (absBytes >= BytesInTerabyte) return (Bytes / BytesInTerabyte, TerabyteSymbol);
    if (absBytes >= BytesInGigabyte) return (Bytes / BytesInGigabyte, GigabyteSymbol);
    if (absBytes >= BytesInMegabyte) return (Bytes / BytesInMegabyte, MegabyteSymbol);
    if (absBytes >= BytesInKilobyte) return (Bytes / BytesInKilobyte, KilobyteSymbol);
    if (absBytes >= 1) return (Bytes, ByteSymbol);
    return (Bits, BitSymbol);
}

