/// </summary>
/// <param name="format">A standard or custom numeric format string.</param>
/// <param name="provider">An object that supplies culture-specific formatting information.</param>
/// <returns>A formatted string representing this data size.</returns>
public string ToString(string? format, IFormatProvider? formatProvider = null)
{
    format ??= "0.## ";
    formatProvider ??= CultureInfo.CurrentCulture;

    if (!format.Contains('#') && !format.Contains('0'))
    {
        format = "0.## " + format;
    }

    var culture = formatProvider as CultureInfo ?? CultureInfo.CurrentCulture;

    // Try each unit symbol: find it, extract the numeric format, and format the value.
    if (TryFormatUnit(format, TerabyteSymbol, Terabytes, culture, formatProvider, out var result)) return result;
    if (TryFormatUnit(format, GigabyteSymbol, Gigabytes, culture, formatProvider, out result)) return result;
    if (TryFormatUnit(format, MegabyteSymbol, Megabytes, culture, formatProvider, out result)) return result;
    if (TryFormatUnit(format, KilobyteSymbol, Kilobytes, culture, formatProvider, out result)) return result;

    if (format.Contains(ByteSymbol, StringComparison.Ordinal))
        return Bytes.ToString(format.Replace(ByteSymbol, "B"), formatProvider);

    if (format.Contains(BitSymbol, StringComparison.Ordinal))
        return ((double)Bits).ToString(format.Replace(BitSymbol, "b"), formatProvider);

    var (value, symbol) = GetLargestWholeNumber();
    return $"{value.ToString(format, formatProvider)} {symbol}";
}

