    string format, string symbol, double unitValue,
    CultureInfo culture, IFormatProvider formatProvider,
    out string result)
{
    if (culture.CompareInfo.IndexOf(format, symbol, CompareOptions.IgnoreCase) != -1)
    {
        result = unitValue.ToString(format.Replace(symbol, symbol), formatProvider);
        return true;
    }
    result = "";
    return false;
